import React, { useState, useContext } from "react";
import "./LoginPopup.css";
import { assets } from "../../assets/assets";
import { StoreContext } from "../../context/StoreContext";
import axios from "axios";
function LoginPopup({ setShowLogin }) {
  const { url, setToken } = useContext(StoreContext);

  const [currState, setCurrState] = useState("Login");
  const [data, setData] = useState({
    name: "",
    email: "",
    password: "",
  });

  const onChangeHandler = (event) => {
    const name = event.target.name;
    const value = event.target.value;
    setData((data) => ({ ...data, [name]: value }));
  };

  // const onLogin = async (event) => {
  //   event.preventDefault();
  //   let newUrl = url;
  //   if (currState === "Login") {
  //     newUrl += "/api/user/login";
  //   } else {
  //     newUrl += "/api/user/register";
  //   }

  //   try {
  //     const response = await axios.post(newUrl, data);

  //     if (response.data.success) {
  //       setToken(response.data.token);
  //       localStorage.setItem("token", response.data.token);
  //       alert(response.data.message || "Login successful!");
  //       setShowLogin(false);
  //     } else {
  //       alert(response.data.message || "Something went wrong!");
  //     }
  //   } catch (error) {
  //     console.error("Login error:", error);
  //     alert("Network error. Please check your backend connection.");
  //   }
  // };


  const onLogin = async (event) => {
    event.preventDefault();
    
    try {
        const response = await axios.post(
            currState === "Login" ? `${url}/api/user/login` : `${url}/api/user/register`,
            data
        );

        console.log("Login response:", response.data); // Debug

        if (response.data.success) {
            const token = response.data.token;
            
            // Clean token - remove any whitespace
            const cleanToken = token.trim();
            
            console.log("Token received:", cleanToken.substring(0, 20) + "...");
            
            // Save to context and localStorage
            setToken(cleanToken);
            localStorage.setItem("token", cleanToken);
            
            // Test token immediately
            try {
                const testResponse = await axios.post(
                    url + "/api/cart/get",
                    {},
                    {
                        headers: {
                            'Authorization': `Bearer ${cleanToken}`
                        }
                    }
                );
                console.log("Token test successful:", testResponse.data);
            } catch (testError) {
                console.error("Token test failed:", testError);
            }
            
            alert(response.data.message || "Login successful!");
            setShowLogin(false);
        } else {
            alert(response.data.message || "Something went wrong!");
        }
    } catch (error) {
        console.error("Login error:", error);
        alert(error.response?.data?.message || "Network error. Please check your backend connection.");
    }
};
  return (
    <div className="login-popup">
      <form onSubmit={onLogin} className="login-popup-container">
        <div className="login-popup-title">
          <h2>{currState}</h2>
          <img
            onClick={() => setShowLogin(false)}
            src={assets.cross_icon}
            alt=""
          />
        </div>
        <div className="login-popup-inputs">
          {currState === "Login" ? (
            <></>
          ) : (
            <input
              name="name"
              onChange={onChangeHandler}
              value={data.name}
              type="text"
              placeholder="Your name"
              required
            />
          )}

          <input
            name="email"
            onChange={onChangeHandler}
            value={data.email}
            type="email"
            placeholder="Your email"
            required
          />
          <input
            name="password"
            onChange={onChangeHandler}
            value={data.password}
            type="password"
            placeholder="password"
            required
          />
        </div>
        <button type="submit">
          {currState === "Sing Up" ? "Create Account" : "Login"}
        </button>
        <div className="login-popup-condition">
          <input type="checkbox" required />
          <p> By continuing a agree to the terms of use & privacy policy</p>
        </div>
        {currState === "Login" ? (
          <p>
            create a new Account?{" "}
            <span onClick={() => setCurrState("Sign Up")}>Click hare</span>
          </p>
        ) : (
          <p>
            {" "}
            Already have an account?
            <span onClick={() => setCurrState("")}>Login here</span>
          </p>
        )}
      </form>
    </div>
  );
}

export default LoginPopup;
